// HEIAN Wallet - Inpage Provider (EIP-6963 + EIP-1193 Compliant)
// Injects window.ethereum and announces via EIP-6963

(function() {
  'use strict';
  
  console.log('🔥 HEIAN Wallet inpage provider loading...');
  
  // Generate unique UUID for this provider session
  function generateUUID() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  }
  
  const providerUUID = generateUUID();
  
  // EIP-1193 Provider Implementation
  class HeianProvider {
    constructor() {
      this.isHeianWallet = true;
      this.isMetaMask = false; // Don't pretend to be MetaMask
      this.isTempo = true; // Identify as Tempo-native
      this.chainId = '0xa5bf'; // Tempo Moderato testnet: 42431
      this.networkVersion = '42431';
      this.selectedAddress = null;
      this._events = {};
      this._nextId = 1;
      this._pendingRequests = new Map();
      
      // Listen for responses from content script
      window.addEventListener('message', this._handleResponse.bind(this));
      
      console.log('✅ HeianProvider initialized');
    }
    
    // EIP-1193: Primary request method
    async request(args) {
      if (!args || typeof args !== 'object' || !args.method) {
        throw new Error('Invalid request arguments');
      }
      
      console.log('📞 provider.request:', args.method, args.params);
      
      // Handle some methods locally for speed
      switch (args.method) {
        case 'eth_chainId':
          return this.chainId;
        
        case 'net_version':
          return this.networkVersion;
        
        case 'eth_accounts':
          return this.selectedAddress ? [this.selectedAddress] : [];
        
        default:
          // Send to background for processing
          return this._sendRequest(args.method, args.params || []);
      }
    }
    
    // Internal: Send request to content script
    _sendRequest(method, params) {
      return new Promise((resolve, reject) => {
        const id = this._nextId++;
        
        this._pendingRequests.set(id, { resolve, reject });
        
        // Post message to content script
        window.postMessage({
          target: 'heian-content',
          source: 'heian-inpage',
          method,
          params,
          id
        }, '*');
        
        // Timeout after 60 seconds
        setTimeout(() => {
          if (this._pendingRequests.has(id)) {
            this._pendingRequests.delete(id);
            reject(new Error('Request timeout'));
          }
        }, 60000);
      });
    }
    
    // Internal: Handle responses from content script
    _handleResponse(event) {
      if (event.source !== window) return;
      if (!event.data || event.data.target !== 'heian-inpage') return;

      // Handle accountsChanged broadcasts (no request ID, sent when wallet unlocks/locks)
      if (event.data.type === 'accountsChanged') {
        console.log('🔄 Received accountsChanged event:', event.data.accounts);
        this.selectedAddress = event.data.accounts[0] || null;
        this._emit('accountsChanged', event.data.accounts);
        return;
      }

      // Handle request-response messages (with ID)
      const { id, result, error } = event.data;
      const pending = this._pendingRequests.get(id);

      if (pending) {
        this._pendingRequests.delete(id);

        if (error) {
          pending.reject(new Error(error.message || 'Request failed'));
        } else {
          // Update state based on response
          if (event.data.method === 'eth_requestAccounts' && result && result[0]) {
            this.selectedAddress = result[0];
            this._emit('accountsChanged', result);
          }

          pending.resolve(result);
        }
      }
    }
    
    // EIP-1193: Event emitter
    on(event, callback) {
      if (!this._events[event]) {
        this._events[event] = [];
      }
      this._events[event].push(callback);
    }
    
    removeListener(event, callback) {
      if (this._events[event]) {
        this._events[event] = this._events[event].filter(cb => cb !== callback);
      }
    }
    
    _emit(event, data) {
      if (this._events[event]) {
        this._events[event].forEach(callback => {
          try {
            callback(data);
          } catch (err) {
            console.error('Event callback error:', err);
          }
        });
      }
    }
    
    // Legacy: send() for backwards compatibility
    send(methodOrPayload, paramsOrCallback) {
      if (typeof methodOrPayload === 'string') {
        return this.request({ method: methodOrPayload, params: paramsOrCallback });
      }
      
      // Legacy callback format
      const callback = paramsOrCallback;
      this.request(methodOrPayload)
        .then(result => callback(null, { result }))
        .catch(error => callback(error));
    }
    
    // Legacy: sendAsync()
    sendAsync(payload, callback) {
      this.request(payload)
        .then(result => callback(null, { 
          id: payload.id, 
          jsonrpc: '2.0', 
          result 
        }))
        .catch(error => callback(error));
    }
    
    // Legacy: enable()
    async enable() {
      return this.request({ method: 'eth_requestAccounts' });
    }
    
    // Connection status
    isConnected() {
      return this.selectedAddress !== null;
    }
  }
  
  // Create provider instance
  const heianProvider = new HeianProvider();
  
  // EIP-6963: Provider Info
  // HEIAN Wallet SVG icon (purple gradient with "HW" letters)
  const iconUrl = 'data:image/png;base64,';

  const providerInfo = {
    uuid: providerUUID,
    name: 'HEIAN Wallet',
    icon: iconUrl,
    rdns: 'io.heian.wallet',
    walletId: 'io.heian.wallet'
  };
  
  // EIP-6963: Announce provider
  function announceProvider() {
    const event = new CustomEvent('eip6963:announceProvider', {
      detail: Object.freeze({
        info: providerInfo,
        provider: heianProvider
      })
    });
    
    window.dispatchEvent(event);
    console.log('📢 EIP-6963: HEIAN Wallet announced');
  }
  
  // EIP-6963: Listen for discovery requests
  window.addEventListener('eip6963:requestProvider', () => {
    announceProvider();
  });
  
  // Announce immediately
  announceProvider();
  
  // Also inject as window.ethereum for legacy dApps
  if (!window.ethereum) {
    window.ethereum = heianProvider;
    console.log('✅ window.ethereum injected (legacy)');
  } else {
    console.log('⚠️ window.ethereum already exists (probably MetaMask)');
  }
  
  // Announce that Ethereum provider is ready
  window.dispatchEvent(new Event('ethereum#initialized'));
  
  console.log('✅ HEIAN Wallet provider ready (EIP-6963 + EIP-1193)');
})();
